103	  By Theorem~34 and Remark~32 of Kriz, the hypothesis on \(E[p]\) implies a congruence of \(p\)-adic modular forms \(f\equiv G\pmod{p}\), where \(G\) is a weight-two Eisenstein series of type \(E_2^{\phi,\phi^{-1},(N)}\). Viewing \(G\) as a \(p\)-adic modular form, its Serre--Tate expansions define \(\mathbb{Z}_p^{\mathrm{ur}}\)-valued measures \(\mu_{G,\mathfrak{a}}\) on \(\mathbb{Z}_p\) by the same rule as in the proof of \cref{thm:BDP}. The corresponding measure element \(\Lcal_G \in \Lambda^{\mathrm{ur}}\) is defined by \(\Lcal_G(\xi) := \mathscr{L}_{v,\eta}(G, \eta^{-1}\xi)\). The interpolation computation of Kriz (Prop.~37 of \emph{op.\,cit.}, with \(\chi^{-1} = \xi\mathbf{N}_K\), \(\psi_1 = \phi\), \(\psi_2 = \phi^{-1} = \psi\omega^{-1}\)) then gives \(\Lcal_G = \mathcal{E}_{\phi,\psi}^\iota\cdot\Lcal_\phi\), using that \(\mathcal{E}_{\phi,\psi}(\xi^{-1}) = \Xi_{\xi^{-1}\mathbf{N}_K^{-1}}(\phi,\psi\omega^{-1}, N_+, N_-, N_0)\). On the other hand, the congruence \(f\equiv G\pmod{p}\) implies \(\Lcal_E \equiv (\Lcal_G)^2 \pmod{p\Lambda^{\mathrm{ur}}}\). Combining these two identities yields the stated congruence.
104	\end{proof}
105	
106	\begin{corollary}[mu/lambda formula for \(\Lcal_E\)]
107	  \label{cor:Kriz}
108	  \lean{MR4372220.Analytic.krizLambda}
109	  \uses{thm:kriz, def:iwasawa-algebra}
110	  % SOURCE: [Castella--Grossi--Lee--Skinner, MR4372220, §Analytic side, Comparison II, Thm.~\ref{cor:Kriz}] (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
111	  % SOURCE QUOTE: "Assume that $E[p]^{ss}=\mathbb{F}_p(\phi)\oplus\mathbb{F}_p(\psi)$ as $G_\bQ$-modules, with the characters $\phi, \psi$ labeled so that $p\nmid\mathrm{cond}(\phi)$, and suppose $\phi\neq\mathds{1}$. Then $\mu(\Lcal_E)=0$ and $\lambda(\Lcal_E)=\lambda(\Lcal_\phi)+\lambda(\Lcal_\psi)+\sum_{w\in S}\bigl\{\lambda(\mathcal{P}_w(\phi))+\lambda(\mathcal{P}_w(\psi))-\lambda(\mathcal{P}_w(E))\bigr\}$."
112	  \textit{Source: Castella--Grossi--Lee--Skinner, MR4372220, §Analytic side, Comparison II, Theorem~\(\ref{cor:Kriz}\).}
113	
114	  Under the hypotheses of \cref{thm:kriz}, we have \(\mu(\Lcal_E) = 0\) and
115	  \[
116	    \lambda(\Lcal_E)
117	    = \lambda(\Lcal_\phi) + \lambda(\Lcal_\psi)
118	      + \sum_{w\in S}\bigl\{\lambda(\mathcal{P}_w(\phi)) + \lambda(\mathcal{P}_w(\psi)) - \lambda(\mathcal{P}_w(E))\bigr\},
119	  \]
120	  where \(S\) is the set of primes \(w\nmid p\) in \(\Sigma\) split in \(K\).
121	\end{corollary}
122	
123	% SOURCE QUOTE PROOF: "Since $K$ satisfies (\ref{eq:intro-Heeg}) and (\ref{eq:intro-spl}), the conductors of both $\phi$ and $\psi$ are only divisible by primes split in $K$, and hence the vanishing of $\mu(\mathcal{L}_E)$ follows immediately from the congruence of Theorem~\ref{thm:kriz} and Hida's result \cite{hidamu=0} (note that the factors $\mathcal{P}_w(\phi)$ and $\mathcal{P}_w(\psi)$ also have vanishing $\mu$-invariant, since again the primes $w$ are split in $K$)."
124	\begin{proof}
125	  \uses{thm:kriz}
126	  Since \(K\) satisfies the Heegner and split hypotheses, the conductors of \(\phi\) and \(\psi\) are only divisible by primes split in \(K\). Therefore \(\mu(\Lcal_E) = 0\) follows from the congruence of \cref{thm:kriz} and Hida's theorem \(\mu = 0\) for Katz \(p\)-adic \(L\)-functions (note that the Euler factor terms \(\mathcal{P}_w(\phi)\) and \(\mathcal{P}_w(\psi)\) also have vanishing \(\mu\)-invariant, since the primes \(w\) are split in \(K\)).
127	
128	  For the \(\lambda\)-invariant formula, the involution \(\gamma\mapsto\gamma^{-1}\) of \(\Lambda\) preserves \(\lambda\)-invariants, so
129	  \[
130	    \lambda(\mathcal{P}_w(\theta)^2) = \lambda(\mathcal{P}_w(\theta)) + \lambda(\mathcal{P}_{\bar{w}}(\theta)),
131	  \]
132	  using that complex conjugation acts as inversion on \(\Gamma\). For the term \(\mathcal{E}_{\phi,\psi}\) from \cref{thm:kriz} we therefore get
133	  \[
134	    \lambda((\mathcal{E}_{\phi,\psi}^\iota)^2)
135	    = \sum_{w\mid N_0 N_-}\lambda(\mathcal{P}_w(\phi)) + \sum_{w\mid N_0 N_+}\lambda(\mathcal{P}_w(\psi)),
136	  \]
137	  where \(w\) runs over all divisors. Using the congruence relations in \cref{thm:kriz} (in particular \(a_\ell\equiv 0\pmod{p}\) for \(\ell\mid N_0\)), this rewrites as
138	  \[
139	    \lambda((\mathcal{E}_{\phi,\psi}^\iota)^2)
140	    = \sum_{w\in S}\bigl\{\lambda(\mathcal{P}_w(\phi)) + \lambda(\mathcal{P}_w(\psi)) - \lambda(\mathcal{P}_w(E))\bigr\}.
141	  \]
142	  Since \(\psi = \phi^{-1}\omega\), the functional equation for the Katz \(p\)-adic \(L\)-function gives \(\lambda(\Lcal_\psi) = \lambda(\Lcal_\phi)\). The result now follows from \cref{thm:kriz} combined with these two identities.
143	\end{proof}
144	
145	\begin{theorem}[Analytic-algebraic lambda comparison]
146	  \label{mulambda}
147	  \lean{MR4372220.Analytic.mulambda}
148	  \uses{cor:Kriz, MAINalgside}
149	  % SOURCE: [Castella--Grossi--Lee--Skinner, MR4372220, §Analytic side, Comparison II, Thm.~\ref{mulambda}] (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
150	  % SOURCE QUOTE: "Assume that $E[p]^{ss}=\mathbb{F}_p(\phi)\oplus\mathbb{F}_p(\psi)$ with $\phi\vert_{G_p}\neq\mathds{1},\omega$. Then $\mu(\mathcal{L}_E)=\mu(\mathfrak{X}_E)=0$ and $\lambda(\Lcal_E)=\lambda(\mathfrak{X}_E)$."
151	  \textit{Source: Castella--Grossi--Lee--Skinner, MR4372220, §Analytic side, Comparison II, Theorem~\(\ref{mulambda}\).}
152	
153	  Assume \(E[p]^{ss} = \mathbb{F}_p(\phi)\oplus\mathbb{F}_p(\psi)\) with \(\phi|_{G_p}\neq\mathds{1},\omega\). Then
154	  \[
155	    \mu(\Lcal_E) = \mu(\mathfrak{X}_E) = 0
156	    \quad\text{and}\quad
157	    \lambda(\Lcal_E) = \lambda(\mathfrak{X}_E).
158	  \]
159	\end{theorem}
160	
161	% SOURCE QUOTE PROOF: "The vanishing of $\mu(\mathfrak{X}_E)$ (resp. $\mu(\mathcal{L}_E)$) has been shown in Proposition~\ref{propmodp} (resp. Theorem~\ref{cor:Kriz}). On the other hand, Iwasawa's main conjecture for $K$ (a theorem of Rubin \cite{rubinmainconj}) yields in particular the equalities $\lambda(\Lcal_\phi)=\lambda(\mathfrak{X}_\phi)$ and $\lambda(\Lcal_\psi)=\lambda(\mathfrak{X}_\psi)$. The combination of Theorem~\ref{MAINalgside} and Theorem~\ref{cor:Kriz} therefore yields the result."
162	\begin{proof}
163	  \uses{cor:Kriz, MAINalgside}
164	  The vanishing \(\mu(\mathfrak{X}_E) = 0\) is the algebraic conclusion of \cref{MAINalgside}, and \(\mu(\Lcal_E) = 0\) is \cref{cor:Kriz}. For the \(\lambda\)-equality, Rubin's proof of Iwasawa's main conjecture for \(K\) gives in particular \(\lambda(\Lcal_\phi) = \lambda(\mathfrak{X}_\phi)\) and \(\lambda(\Lcal_\psi) = \lambda(\mathfrak{X}_\psi)\). Substituting these equalities into the formula of \cref{cor:Kriz} and comparing with the algebraic comparison formula of \cref{MAINalgside} (which expresses \(\lambda(\mathfrak{X}_E)\) in terms of \(\lambda(\mathfrak{X}_\phi)\), \(\lambda(\mathfrak{X}_\psi)\), and the local Euler factors) yields \(\lambda(\Lcal_E) = \lambda(\mathfrak{X}_E)\).
165	\end{proof}
